// Get trending players (most added/dropped based on real transactions)
playerRoutes.get('/trending', optionalAuthMiddleware, async (c) => {
  const db = c.get('db');
  const direction = c.req.query('direction') || 'up'; // 'up' or 'down'

  try {
    // Look at processed transactions from the last 14 days
    const cutoff = new Date(Date.now() - 14 * 24 * 60 * 60 * 1000);

    let trendingRows: { playerId: string; count: number }[];

    if (direction === 'up') {
      // Most added players: count add/waiver transactions per playerId
      trendingRows = await db
        .select({
          playerId: schema.transactions.playerId,
          count: sql<number>`count(*)`.as('cnt'),
        })
        .from(schema.transactions)
        .where(
          and(
            sql`${schema.transactions.type} IN ('add', 'waiver')`,
            eq(schema.transactions.status, 'processed'),
            sql`${schema.transactions.createdAt} >= ${cutoff.getTime() / 1000}`,
            sql`${schema.transactions.playerId} IS NOT NULL`
          )
        )
        .groupBy(schema.transactions.playerId)
        .orderBy(sql`cnt DESC`)
        .limit(10) as any;
    } else {
      // Most dropped players: count drop transactions per dropPlayerId
      trendingRows = await db
        .select({
          playerId: schema.transactions.dropPlayerId,
          count: sql<number>`count(*)`.as('cnt'),
        })
        .from(schema.transactions)
        .where(
          and(
            sql`${schema.transactions.type} IN ('drop', 'waiver')`,
            eq(schema.transactions.status, 'processed'),
            sql`${schema.transactions.createdAt} >= ${cutoff.getTime() / 1000}`,
            sql`${schema.transactions.dropPlayerId} IS NOT NULL`
          )
        )
        .groupBy(schema.transactions.dropPlayerId)
        .orderBy(sql`cnt DESC`)
        .limit(10) as any;
    }

    // If no transaction data yet, fall back to active players
    if (!trendingRows || trendingRows.length === 0) {
      const fallbackPlayers = await db.query.nflPlayers.findMany({
        where: eq(schema.nflPlayers.status, 'active'),
        limit: 10,
      });
      return c.json({
        trending: fallbackPlayers.map((p) => ({
          ...p,
          trendDirection: direction,
          trendValue: 0,
          ownedPct: 0,
        })),
      });
    }

    // Fetch full player details for trending players
    const playerIds = trendingRows.map((r) => r.playerId).filter(Boolean) as string[];
    const players = playerIds.length > 0
      ? await db.query.nflPlayers.findMany({
          where: inArray(schema.nflPlayers.id, playerIds),
        })
      : [];
    const playerMap = new Map(players.map((p) => [p.id, p]));

    // Count total teams across all leagues for ownership %
    const teamCountResult = await db
      .select({ total: sql<number>`count(*)` })
      .from(schema.teams);
    const totalTeams = (teamCountResult[0]?.total as number) || 1;

    // For each trending player, count how many teams roster them
    const trending = trendingRows
      .map((row) => {
        const player = playerMap.get(row.playerId);
        if (!player) return null;
        return {
          ...player,
          trendDirection: direction,
          trendValue: row.count,
          ownedPct: 0, // Will be filled below
        };
      })
      .filter(Boolean);

    // Batch ownership % lookup
    if (playerIds.length > 0) {
      const rosterCounts = await db
        .select({
          playerId: schema.rosterSpots.playerId,
          count: sql<number>`count(DISTINCT ${schema.rosterSpots.teamId})`.as('cnt'),
        })
        .from(schema.rosterSpots)
        .where(inArray(schema.rosterSpots.playerId, playerIds))
        .groupBy(schema.rosterSpots.playerId) as any[];

      const ownershipMap = new Map<string, number>(
        rosterCounts.map((r: any) => [r.playerId, Math.round((r.count / totalTeams) * 100)])
      );
      for (const t of trending) {
        if (t) t.ownedPct = ownershipMap.get((t as any).id) || 0;
      }
    }

    return c.json({ trending });
  } catch (error) {
    console.error('Get trending error:', error);
    return c.json({ error: 'Failed to fetch trending players' }, 500);
  }
});

